1	/**
2	 * Mock adapter — returns canned output for test mode.
3	 *
4	 * OracleAIClient uses this adapter when run with `{ mode: 'test' }`. It lets
5	 * the entire pipeline (compiler → router → adapter → usage normalizer →
6	 * validator) be exercised without any provider SDK or API key.
7	 *
8	 * This adapter is NOT a fallback for production. If a real adapter throws
9	 * ProviderAdapterNotImplementedError in production mode, OracleAIClient
10	 * surfaces that error — it does not silently swap in mock output.
11	 */
12	
13	import type {
14	  OracleObjectResult,
15	  OracleTextResult,
16	  OracleUsage,
17	} from '../client/types';
18	import type { OracleProvider } from '../routes';
19	import type {
20	  GenerateObjectArgs,
21	  GenerateTextArgs,
22	  OracleProviderAdapter,
23	} from './types';
24	
25	export interface MockAdapterOptions {
26	  /** What provider this mock should impersonate. Useful for testing dispatch. */
27	  provider: OracleProvider;
28	  /** Canned text output for generateText. */
29	  cannedText?: string;
30	  /** Canned object output for generateObject. */
31	  cannedObject?: unknown;
32	  /** Fixed latency to report. Defaults to 1ms. */
33	  latencyMs?: number;
34	}
35	
36	export class MockProviderAdapter implements OracleProviderAdapter {
37	  readonly provider: OracleProvider;
38	  private readonly cannedText: string;
39	  private readonly cannedObject: unknown;
40	  private readonly latencyMs: number;
41	
42	  constructor(opts: MockAdapterOptions) {
43	    this.provider = opts.provider;
44	    this.cannedText = opts.cannedText ?? `[mock ${opts.provider}] OK`;
45	    this.cannedObject = opts.cannedObject ?? { ok: true, provider: opts.provider };
46	    this.latencyMs = opts.latencyMs ?? 1;
47	  }
48	
49	  async generateText(args: GenerateTextArgs): Promise<OracleTextResult> {
50	    return {
51	      text: this.cannedText,
52	      usage: this.makeUsage(args.plan.blocks.map((b) => b.tokenEstimate ?? 0).reduce((a, b) => a + b, 0)),
53	      rawResponse: {
54	        mock: true,
55	        provider: this.provider,
56	        routeId: args.route.routeId,
57	        taskType: args.plan.taskType,
58	      },
59	    };
60	  }
61	
62	  async generateObject<TSchema, TOutput>(
63	    args: GenerateObjectArgs<TSchema>,
64	  ): Promise<OracleObjectResult<TOutput>> {
65	    return {
66	      object: this.cannedObject as TOutput,
67	      usage: this.makeUsage(args.plan.blocks.map((b) => b.tokenEstimate ?? 0).reduce((a, b) => a + b, 0)),
68	      rawResponse: {
69	        mock: true,
70	        provider: this.provider,
71	        routeId: args.route.routeId,
72	        taskType: args.plan.taskType,
73	      },
74	    };
75	  }
76	
77	  private makeUsage(inputTokens: number): OracleUsage {
78	    return {
79	      inputTokens,
80	      cachedInputTokens: 0,
81	      outputTokens: 16,
82	      latencyMs: this.latencyMs,
83	      providerRequestId: `mock-${this.provider}-${Date.now()}`,
84	      rawUsageJson: { mock: true, provider: this.provider },
85	    };
86	  }
87	}
