22	const IS_PROD = process.env.NODE_ENV === 'production';
23	
24	function tryAdd(
25	  map: ProviderAdapterMap,
26	  key: OracleProvider,
27	  factory: () => OracleProviderAdapter,
28	): void {
29	  try {
30	    map[key] = factory();
31	  } catch (err) {
32	    if (!IS_PROD) {
33	      // eslint-disable-next-line no-console
34	      console.warn(
35	        `[buildStandardAdapters] skipped ${key}: ${err instanceof Error ? err.message : String(err)}`,
36	      );
37	    }
38	  }
39	}
40	
41	export function buildStandardAdapters(): ProviderAdapterMap {
42	  const map: ProviderAdapterMap = {};
43	  tryAdd(map, 'anthropic', () => new AnthropicAdapter());
44	  tryAdd(map, 'vertex',    () => new VertexGeminiAdapter());
45	  tryAdd(map, 'openai',    () => new OpenAIAdapter());
46	  tryAdd(map, 'deepseek',  () => new DeepSeekAdapter());
47	  tryAdd(map, 'qwen',      () => new QwenAdapter());
48	  return map;
49	}
