1	/**
2	 * ModelRouter — given a routeId, picks the correct provider adapter and
3	 * dispatches the call. Handles fallback dispatch when a primary route
4	 * fails with a known transient or schema-validation error.
5	 *
6	 * The router does NOT pick which route to use for a given task — that
7	 * decision belongs to whoever calls OracleAIClient (chat route, extraction
8	 * worker, etc.). The router only:
9	 *
10	 *   - resolves a routeId → adapter
11	 *   - executes the call
12	 *   - on failure, optionally dispatches the configured Fallback route
13	 *
14	 * Per docs/oracle/01-model-roles-and-routes.md "Model routing rules".
15	 */
16	
17	import type {
18	  OracleObjectResult,
19	  OraclePromptPlan,
20	  OracleTextResult,
21	} from '../client/types';
22	import { getOracleRoute, type OracleModelRoute, type OracleProvider } from '../routes';
23	import {
24	  ProviderAdapterNotImplementedError,
25	  type OracleProviderAdapter,
26	} from '../providers/types';
27	
28	export type ProviderAdapterMap = Partial<Record<OracleProvider, OracleProviderAdapter>>;
29	
30	export interface ModelRouterOptions {
31	  adapters: ProviderAdapterMap;
32	  /**
33	   * If true, when the primary adapter throws a transient or schema error,
34	   * the router will dispatch to the route's fallbackRouteId. Default true.
35	   */
36	  fallbackOnError?: boolean;
37	}
38	
39	export class UnknownRouteError extends Error {
40	  constructor(routeId: string) {
41	    super(
42	      `No OracleModelRoute found for routeId "${routeId}". Routes must be registered in packages/ai/src/routes/catalog.ts.`,
43	    );
44	    this.name = 'UnknownRouteError';
45	  }
46	}
47	
48	export class NoAdapterRegisteredError extends Error {
49	  constructor(provider: OracleProvider) {
50	    super(
51	      `No adapter registered for provider "${provider}". Pass it to ModelRouter via options.adapters.`,
52	    );
53	    this.name = 'NoAdapterRegisteredError';
54	  }
55	}
56	
57	export class ModelRouter {
58	  private readonly adapters: ProviderAdapterMap;
59	  private readonly fallbackOnError: boolean;
60	
61	  constructor(opts: ModelRouterOptions) {
62	    this.adapters = opts.adapters;
63	    this.fallbackOnError = opts.fallbackOnError ?? true;
64	  }
65	
66	  /** Resolve a route + adapter pair, or throw with a descriptive error. */
67	  resolve(routeId: string): { route: OracleModelRoute; adapter: OracleProviderAdapter } {
68	    const route = getOracleRoute(routeId);
69	    if (!route) throw new UnknownRouteError(routeId);
70	    const adapter = this.adapters[route.provider];
71	    if (!adapter) throw new NoAdapterRegisteredError(route.provider);
72	    return { route, adapter };
73	  }
74	
75	  async generateText(
76	    plan: OraclePromptPlan,
77	    providerOptions?: Record<string, unknown>,
78	  ): Promise<OracleTextResult> {
79	    return this.dispatch(plan, (adapter, route) =>
80	      adapter.generateText({ plan, route, providerOptions }),
81	    );
82	  }
83	
84	  async generateObject<TSchema, TOutput>(
85	    plan: OraclePromptPlan,
86	    schema: TSchema,
87	    providerOptions?: Record<string, unknown>,
88	  ): Promise<OracleObjectResult<TOutput>> {
89	    return this.dispatch(plan, (adapter, route) =>
90	      adapter.generateObject<TSchema, TOutput>({ plan, route, schema, providerOptions }),
91	    );
92	  }
93	
94	  private async dispatch<T>(
95	    plan: OraclePromptPlan,
96	    call: (adapter: OracleProviderAdapter, route: OracleModelRoute) => Promise<T>,
97	  ): Promise<T> {
98	    const { route, adapter } = this.resolve(plan.routeId);
99	    try {
100	      return this.withRouteMetadata(await call(adapter, route), route);
101	    } catch (err) {
102	      if (!this.fallbackOnError) throw err;
103	      if (!route.fallbackRouteId) throw err;
104	      if (!this.shouldFallback(err)) throw err;
105	      // Dispatch to fallback. Rebuild the plan with the fallback routeId so
106	      // observability records reflect which route actually ran.
107	      const fallbackPlan = { ...plan, routeId: route.fallbackRouteId };
108	      const { route: fbRoute, adapter: fbAdapter } = this.resolve(fallbackPlan.routeId);
109	      return this.withRouteMetadata(await call(fbAdapter, fbRoute), fbRoute, route.routeId, err);
110	    }
111	  }
112	
113	  private withRouteMetadata<T>(
114	    result: T,
115	    route: OracleModelRoute,
116	    fellBackFromRouteId?: string,
117	    fallbackError?: unknown,
118	  ): T {
119	    if (!result || typeof result !== 'object') return result;
120	    return {
121	      ...(result as Record<string, unknown>),
122	      routeId: route.routeId,
123	      provider: route.provider,
124	      modelId: route.modelId,
125	      fellBackFromRouteId,
126	      fallbackReason: fallbackError ? this.fallbackReason(fallbackError) : undefined,
127	    } as T;
128	  }
129	
130	  private fallbackReason(err: unknown): string {
131	    if (err instanceof Error) {
132	      const msg = err.message || err.name;
133	      return msg.length > 100 ? `${msg.slice(0, 97)}...` : msg;
134	    }
135	    const msg = String(err);
136	    return msg.length > 100 ? `${msg.slice(0, 97)}...` : msg;
137	  }
138	
139	  /**
140	   * Conservative fallback policy. Falls back on:
141	   *   - provider adapter not yet implemented (R2 transitional state)
142	   *   - network/timeout errors (well-known node fetch error names)
143	   *   - explicit rate-limit / 429 markers
144	   *
145	   * Does NOT fall back on:
146	   *   - validation failures (those have their own repair flow)
147	   *   - assertion errors from ContextCompiler
148	   */
149	  private shouldFallback(err: unknown): boolean {
150	    if (err instanceof ProviderAdapterNotImplementedError) return true;
151	    if (err instanceof Error) {
152	      const msg = err.message.toLowerCase();
153	      if (msg.includes('429') || msg.includes('rate limit')) return true;
154	      if (msg.includes('timeout') || msg.includes('econnreset') || msg.includes('socket hang up')) return true;
155	      if (err.name === 'FetchError' || err.name === 'AbortError') return true;
156	    }
157	    return false;
158	  }
159	}
