1	/**
2	 * UsageNormalizer — maps provider-native usage objects into OracleUsage.
3	 *
4	 * Each provider exposes cache + reasoning tokens under a different field
5	 * name. We normalize once at the adapter boundary so UsageLogger always
6	 * sees the same shape.
7	 *
8	 * The raw provider object is preserved in OracleUsage.rawUsageJson for
9	 * audit and debugging.
10	 */
11	
12	import type { OracleProvider } from '../routes';
13	import type { OracleUsage } from '../client/types';
14	
15	export interface AnthropicUsageRaw {
16	  input_tokens?: number;
17	  output_tokens?: number;
18	  cache_creation_input_tokens?: number;
19	  cache_read_input_tokens?: number;
20	}
21	
22	export interface VertexUsageRaw {
23	  promptTokenCount?: number;
24	  candidatesTokenCount?: number;
25	  cachedContentTokenCount?: number;
26	  thoughtsTokenCount?: number;
27	  totalTokenCount?: number;
28	}
29	
30	export interface OpenAIUsageRaw {
31	  prompt_tokens?: number;
32	  completion_tokens?: number;
33	  prompt_tokens_details?: { cached_tokens?: number };
34	  completion_tokens_details?: { reasoning_tokens?: number };
35	  total_tokens?: number;
36	}
37	
38	export interface NormalizeArgs {
39	  provider: OracleProvider;
40	  raw: unknown;
41	  latencyMs: number;
42	  providerRequestId?: string;
43	}
44	
45	export interface DeepSeekUsageRaw {
46	  prompt_tokens?: number;
47	  completion_tokens?: number;
48	  prompt_cache_hit_tokens?: number;
49	  prompt_cache_miss_tokens?: number;
50	  completion_tokens_details?: { reasoning_tokens?: number };
51	  total_tokens?: number;
52	}
53	
54	export function normalizeUsage(args: NormalizeArgs): OracleUsage {
55	  const { provider, raw, latencyMs, providerRequestId } = args;
56	  switch (provider) {
57	    case 'anthropic':
58	      return normalizeAnthropic(raw as AnthropicUsageRaw, latencyMs, providerRequestId);
59	    case 'vertex':
60	      return normalizeVertex(raw as VertexUsageRaw, latencyMs, providerRequestId);
61	    case 'openai':
62	      return normalizeOpenAI(raw as OpenAIUsageRaw, latencyMs, providerRequestId);
63	    case 'deepseek':
64	      return normalizeDeepSeek(raw as DeepSeekUsageRaw, latencyMs, providerRequestId);
65	    case 'qwen':
66	      // Qwen via DashScope OpenAI-compat returns the OpenAI usage shape.
67	      return normalizeOpenAI(raw as OpenAIUsageRaw, latencyMs, providerRequestId);
68	  }
69	}
70	
71	function normalizeAnthropic(
72	  raw: AnthropicUsageRaw,
73	  latencyMs: number,
74	  providerRequestId?: string,
75	): OracleUsage {
76	  return {
77	    inputTokens: raw.input_tokens,
78	    outputTokens: raw.output_tokens,
79	    cachedInputTokens: raw.cache_read_input_tokens,
80	    cacheWriteTokens: raw.cache_creation_input_tokens,
81	    latencyMs,
82	    providerRequestId,
83	    rawUsageJson: raw,
84	  };
85	}
86	
87	function normalizeVertex(
88	  raw: VertexUsageRaw,
89	  latencyMs: number,
90	  providerRequestId?: string,
91	): OracleUsage {
92	  return {
93	    inputTokens: raw.promptTokenCount,
94	    outputTokens: raw.candidatesTokenCount,
95	    cachedInputTokens: raw.cachedContentTokenCount,
96	    reasoningTokens: raw.thoughtsTokenCount,
97	    latencyMs,
98	    providerRequestId,
99	    rawUsageJson: raw,
100	  };
101	}
102	
103	function normalizeOpenAI(
104	  raw: OpenAIUsageRaw,
105	  latencyMs: number,
106	  providerRequestId?: string,
107	): OracleUsage {
108	  return {
109	    inputTokens: raw.prompt_tokens,
110	    outputTokens: raw.completion_tokens,
111	    cachedInputTokens: raw.prompt_tokens_details?.cached_tokens,
112	    reasoningTokens: raw.completion_tokens_details?.reasoning_tokens,
113	    latencyMs,
114	    providerRequestId,
115	    rawUsageJson: raw,
116	  };
117	}
118	
119	/** DeepSeek surfaces cache hits/misses in dedicated top-level fields. */
120	function normalizeDeepSeek(
121	  raw: DeepSeekUsageRaw,
122	  latencyMs: number,
123	  providerRequestId?: string,
124	): OracleUsage {
125	  return {
126	    inputTokens: raw.prompt_tokens,
127	    outputTokens: raw.completion_tokens,
128	    cachedInputTokens: raw.prompt_cache_hit_tokens,
129	    reasoningTokens: raw.completion_tokens_details?.reasoning_tokens,
130	    latencyMs,
131	    providerRequestId,
132	    rawUsageJson: raw,
133	  };
134	}
